import io.grpc.*;
import io.grpc.stub.StreamObserver;
import java.io.*;
import java.nio.file.*;
import java.util.concurrent.atomic.AtomicLong;

public class FileTransferService extends FileTransferGrpc.FileTransferImplBase {
    private static final int CHUNK_SIZE = 1024 * 1024;
    private final AtomicLong totalBytesProcessed = new AtomicLong(0);

    @Override
    public StreamObserver<TransferRequest> transferFile(StreamObserver<TransferResponse> responseObserver) {
        return new StreamObserver<TransferRequest>() {
            private FileOutputStream fileOutputStream;
            private String fileName;
            private long totalSize;
            private long bytesReceived = 0;

            @Override
            public void onNext(TransferRequest request) {
                try {
                    if (request.hasFileInfo()) {
                        fileName = request.getFileInfo().getFileName();
                        totalSize = request.getFileInfo().getFileSize();
                        fileOutputStream = new FileOutputStream(fileName);
                    } else if (request.hasData()) {
                        byte[] data = request.getData().toByteArray();
                        fileOutputStream.write(data);
                        bytesReceived += data.length;
                        totalBytesProcessed.addAndGet(data.length);
                        
                        TransferResponse response = TransferResponse.newBuilder()
                                .setProgress(TransferProgress.newBuilder()
                                        .setFileName(fileName)
                                        .setBytesReceived(bytesReceived)
                                        .setTotalSize(totalSize)
                                        .setPercentage((int) ((bytesReceived * 100.0) / totalSize)))
                                .build();
                        responseObserver.onNext(response);
                    }
                } catch (IOException e) {
                    responseObserver.onError(Status.INTERNAL.withDescription("File write error").withCause(e).asException());
                }
            }

            @Override
            public void onError(Throwable t) {
                if (fileOutputStream != null) {
                    try {
                        fileOutputStream.close();
                    } catch (IOException ignored) {}
                }
                responseObserver.onError(t);
            }

            @Override
            public void onCompleted() {
                try {
                    if (fileOutputStream != null) {
                        fileOutputStream.close();
                        responseObserver.onNext(TransferResponse.newBuilder()
                                .setSuccess(true)
                                .setMessage("File transfer completed successfully")
                                .build());
                    }
                } catch (IOException e) {
                    responseObserver.onError(Status.INTERNAL.withDescription("Error closing file").withCause(e).asException());
                }
                responseObserver.onCompleted();
            }
        };
    }

    @Override
    public void uploadFile(TransferRequest request, StreamObserver<TransferResponse> responseObserver) {
        try {
            if (request.hasFileInfo()) {
                String fileName = request.getFileInfo().getFileName();
                long fileSize = request.getFileInfo().getFileSize();
                
                Path filePath = Paths.get(fileName);
                Files.createDirectories(filePath.getParent());
                
                try (FileOutputStream fos = new FileOutputStream(fileName)) {
                    if (request.hasData()) {
                        fos.write(request.getData().toByteArray());
                    }
                    responseObserver.onNext(TransferResponse.newBuilder()
                            .setSuccess(true)
                            .setMessage("File uploaded successfully")
                            .build());
                }
            }
        } catch (IOException e) {
            responseObserver.onError(Status.INTERNAL.withDescription("Upload failed").withCause(e).asException());
        }
        responseObserver.onCompleted();
    }

    @Override
    public void downloadFile(TransferRequest request, StreamObserver<TransferResponse> responseObserver) {
        try {
            String fileName = request.getFileInfo().getFileName();
            Path filePath = Paths.get(fileName);
            
            if (!Files.exists(filePath)) {
                responseObserver.onError(Status.NOT_FOUND.withDescription("File not found").asException());
                return;
            }
            
            long fileSize = Files.size(filePath);
            try (FileInputStream fis = new FileInputStream(fileName)) {
                byte[] buffer = new byte[CHUNK_SIZE];
                int bytesRead;
                
                while ((bytesRead = fis.read(buffer)) != -1) {
                    TransferResponse response = TransferResponse.newBuilder()
                            .setData(ByteString.copyFrom(buffer, 0, bytesRead))
                            .build();
                    responseObserver.onNext(response);
                }
            }
            
            responseObserver.onNext(TransferResponse.newBuilder()
                    .setSuccess(true)
                    .setMessage("File downloaded successfully")
                    .build());
            responseObserver.onCompleted();
        } catch (IOException e) {
            responseObserver.onError(Status.INTERNAL.withDescription("Download failed").withCause(e).asException());
        }
    }

    @Override
    public StreamObserver<TransferRequest> streamUpload(StreamObserver<TransferResponse> responseObserver) {
        return new StreamObserver<TransferRequest>() {
            private FileOutputStream fileOutputStream;
            private long totalSize = 0;
            private long bytesReceived = 0;

            @Override
            public void onNext(TransferRequest request) {
                try {
                    if (request.hasFileInfo()) {
                        totalSize = request.getFileInfo().getFileSize();
                        fileOutputStream = new FileOutputStream(request.getFileInfo().getFileName());
                    } else if (request.hasData()) {
                        byte[] data = request.getData().toByteArray();
                        fileOutputStream.write(data);
                        bytesReceived += data.length;
                        totalBytesProcessed.addAndGet(data.length);
                    }
                } catch (IOException e) {
                    responseObserver.onError(Status.INTERNAL.withDescription("Streaming upload error").withCause(e).asException());
                }
            }

            @Override
            public void onError(Throwable t) {
                if (fileOutputStream != null) {
                    try {
                        fileOutputStream.close();
                    } catch (IOException ignored) {}
                }
                responseObserver.onError(t);
            }

            @Override
            public void onCompleted() {
                try {
                    if (fileOutputStream != null) {
                        fileOutputStream.close();
                        responseObserver.onNext(TransferResponse.newBuilder()
                                .setSuccess(true)
                                .setMessage("Streaming upload completed")
                                .build());
                    }
                } catch (IOException e) {
                    responseObserver.onError(Status.INTERNAL.withDescription("Error closing file").withCause(e).asException());
                }
                responseObserver.onCompleted();
            }
        };
    }

    public long getTotalBytesProcessed() {
        return totalBytesProcessed.get();
    }
}

// Server setup
public class FileTransferServer {
    private final int port;
    private final Server server;

    public FileTransferServer(int port) {
        this.port = port;
        this.server = ServerBuilder.forPort(port)
                .addService(new FileTransferService())
                .maxInboundMessageSize(Integer.MAX_VALUE)
                .build();
    }

    public void start() throws IOException {
        server.start();
        System.out.println("Server started on port " + port);
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            System.out.println("Shutting down server...");
            server.shutdown();
        }));
    }

    public void blockUntilShutdown() throws InterruptedException {
        server.awaitTermination();
    }

    public static void main(String[] args) throws IOException, InterruptedException {
        FileTransferServer server = new FileTransferServer(8080);
        server.start();
        server.blockUntilShutdown();
    }
}

// Client implementation
public class FileTransferClient {
    private final ManagedChannel channel;
    private final FileTransferGrpc.FileTransferBlockingStub blockingStub;
    private final FileTransferGrpc.FileTransferStub asyncStub;

    public FileTransferClient(String host, int port) {
        this.channel = ManagedChannelBuilder.forAddress(host, port)
                .usePlaintext()
                .maxInboundMessageSize(Integer.MAX_VALUE)
                .build();
        this.blockingStub = FileTransferGrpc.newBlockingStub(channel);
        this.asyncStub = FileTransferGrpc.newStub(channel);
    }

    public void uploadFile(String fileName) throws IOException {
        Path filePath = Paths.get(fileName);
        long fileSize = Files.size(filePath);
        
        StreamObserver<TransferRequest> requestObserver = asyncStub.transferFile(responseObserver -> {
            System.out.println("Received response: " + responseObserver.getMessage());
        });
        
        try {
            requestObserver.onNext(TransferRequest.newBuilder()
                    .setFileInfo(TransferFileInfo.newBuilder()
                            .setFileName(fileName)
                            .setFileSize(fileSize)
                            .build())
                    .build());
            
            try (FileInputStream fis = new FileInputStream(fileName)) {
                byte[] buffer = new byte[1024 * 1024];
                int bytesRead;
                while ((bytesRead = fis.read(buffer)) != -1) {
                    requestObserver.onNext(TransferRequest.newBuilder()
                            .setData(ByteString.copyFrom(buffer, 0, bytesRead))
                            .build());
                }
            }
            
            requestObserver.onCompleted();
        } catch (Exception e) {
            requestObserver.onError(e);
        }
    }

    public void close() {
        channel.shutdown();
    }
}